// NotificationEvents is the resolver for the notificationEvents field.
func (r *subscriptionResolver) NotificationEvents(
	ctx context.Context,
) (<-chan graph.NotificationEvent, error) {
	user, err := echoutils.GetUserAuthContexts(ctx)
	if err != nil {
		r.logger.Error("Failed to get user from context", "error", err)
		return nil, err
	}

	r.logger.Info("GraphQL notification subscription request received",
		"user_id", user.UserID)

	// Subscribe to notification events via the subscription manager
	eventChan, err := r.subscriptionManager.SubscribeToNotifications(ctx, user.UserID)
	if err != nil {
		r.logger.Error("Failed to subscribe to notification events",
			"error", err,
			"user_id", user.UserID)

		return nil, err
	}

	r.logger.Info("GraphQL notification subscription established successfully",
		"user_id", user.UserID,
		"channel_buffer", cap(eventChan))

	// Start a goroutine to log when events are sent through the channel
	go func() {
		<-ctx.Done()
		r.logger.Info("GraphQL notification subscription context done",
			"user_id", user.UserID)
	}()

	return eventChan, nil
}
